sql:
SELECT artworks.name AS artwork_name, artists.name AS artist_name
FROM artworks
INNER JOIN artists ON artworks.artist_id = artists.artist_id;

external_knowledge:
- 'harvesters of creativity': Artists who create artwork;
- 'golden fruits': Artworks of significant value;
- 'cost of their orchard's bounty': The average price of artworks;
- 'fruits they've borne': Total number of artworks created by an artist;
- 'value of their orchard': The average price of their artworks, indicating the 'value' of their 'orchard'.

sql:
SELECT AVG(price) AS average_price
FROM acquisitions
WHERE source = 'Purchase from a private collector' AND acquisition_date LIKE '1924%';

SELECT DISTINCT artists.name, artists.nationality 
FROM artists 
JOIN artworks ON artists.artist_id = artworks.artist_id;

SELECT curators.name
FROM curators
JOIN exhibitions ON curators.curator_id = exhibitions.curator_id
WHERE exhibitions.attendance = (
    SELECT MAX(attendance) FROM exhibitions
);

SELECT COUNT(artwork_id) 
FROM acquisitions 
WHERE strftime('%Y', acquisition_date) = '2022';

SELECT a.name AS creator_name, w.title AS piece_title
FROM artists a
JOIN artworks w ON a.artist_id = w.artist_id;
